import React, { useState } from 'react';
import { useData } from '../../context/DataContext';

const TaskManager = () => {
  const { staffList, tasks, addTask } = useData();
  const [taskTitle, setTaskTitle] = useState('');
  const [assigneeId, setAssigneeId] = useState('');
  // [MỚI] Thêm state cho ngày tháng và hình thức kỷ luật
  const [dates, setDates] = useState({ startDate: '', deadline: '' });
  const [discipline, setDiscipline] = useState('');

  const handleCreateTask = (e) => {
    e.preventDefault();
    if (!assigneeId) return alert("Vui lòng chọn nhân sự!");
    if (!dates.startDate || !dates.deadline) return alert("Vui lòng chọn đầy đủ ngày tháng!");
    if (!discipline) return alert("Vui lòng nhập hình thức kỷ luật!");

    addTask({ 
      title: taskTitle, 
      assigneeId: parseInt(assigneeId),
      startDate: dates.startDate,
      deadline: dates.deadline,
      discipline: discipline // Lưu hình thức kỷ luật
    });

    // Reset form
    setTaskTitle('');
    setDates({ startDate: '', deadline: '' });
    setDiscipline('');
    alert("Đã giao việc thành công");
  };

  return (
    <div>
      <h2>Giao đầu việc & Thiết lập kỷ luật</h2>
      <form onSubmit={handleCreateTask} style={{ marginBottom: '30px', padding: '20px', background: '#fff', border: '1px solid #ddd', borderRadius: '8px' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          
          <div style={{ display: 'flex', gap: '15px' }}>
            <input 
              placeholder="Tên đầu việc" 
              value={taskTitle} 
              onChange={e => setTaskTitle(e.target.value)} 
              required 
              style={{ flex: 1, padding: '8px' }}
            />
            <select 
              value={assigneeId} 
              onChange={e => setAssigneeId(e.target.value)} 
              required 
              style={{ padding: '8px', width: '200px' }}
            >
              <option value="">-- Chọn nhân sự --</option>
              {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          </div>

          <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
            <div style={{ flex: 1 }}>
                <label style={{ display: 'block', fontSize: '0.9rem', marginBottom: '5px' }}>Ngày bắt đầu:</label>
                <input type="date" value={dates.startDate} onChange={e => setDates({...dates, startDate: e.target.value})} required style={{ width: '100%', padding: '8px' }} />
            </div>
            <div style={{ flex: 1 }}>
                <label style={{ display: 'block', fontSize: '0.9rem', marginBottom: '5px' }}>Deadline (Hạn chót):</label>
                <input type="date" value={dates.deadline} onChange={e => setDates({...dates, deadline: e.target.value})} required style={{ width: '100%', padding: '8px' }} />
            </div>
          </div>

          <div>
             <label style={{ display: 'block', fontSize: '0.9rem', marginBottom: '5px', color: 'red', fontWeight: 'bold' }}>Hình thức kỷ luật nếu vi phạm:</label>
             <input 
                placeholder="Ví dụ: Trừ 5% lương, Nhắc nhở toàn công ty..." 
                value={discipline} 
                onChange={e => setDiscipline(e.target.value)}
                required
                style={{ width: '100%', padding: '8px', border: '1px solid red' }}
             />
          </div>

          <button 
            type="submit" 
            style={{ background: '#003366', color: 'white', border: 'none', padding: '12px', borderRadius: '5px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' }}
          >
            KHỞI TẠO CÔNG VIỆC
          </button>
        </div>
      </form>

      <h3>Danh sách công việc đang theo dõi</h3>
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {tasks.map(t => {
          const staff = staffList.find(s => s.id === t.assigneeId);
          return (
            <li key={t.id} style={{ padding: '15px', borderBottom: '1px solid #eee', background: 'white', marginBottom: '10px' }}>
              <div style={{ fontWeight: 'bold', fontSize: '1.1rem' }}>{t.title}</div>
              <div>Nhân sự: {staff?.name} | Tiến độ: {t.progress}%</div>
              <div style={{ fontSize: '0.9rem', color: '#555' }}>Lịch trình: {t.startDate} đến {t.deadline}</div>
              <div style={{ color: 'red', fontSize: '0.9rem' }}>Kỷ luật: {t.discipline}</div>
            </li>
          );
        })}
      </ul>
    </div>
  );
};

export default TaskManager;
